INSERT INTO `edu_achievement` VALUES
('100', '基于微服务架构的软件工程专业教学改革与实践', '<p>本项目针对当前高校软件工程专业教学中存在的"重理论、轻实践"问题，创新性地引入了基于Spring Cloud微服务架构的教学模式。通过构建一个由14个独立微服务组成的教学实验平台，学生在项目实训中能够直接参与真实的企业级系统开发，涵盖服务注册与发现、配置中心、API网关、负载均衡、熔断降级等核心技术栈。</p><p>项目自2024年9月启动以来，已覆盖3个年级、累计600余名学生，学生的工程项目实践能力显著提升。核心创新点包括：（1）将企业级微服务技术栈融入课堂教学；（2）设计分层递进的实训任务体系；（3）建立校企联动的成果评价机制。学生在全国大学生服务外包创新创业大赛中获国家级二等奖1项、省级一等奖2项。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '200', '111', '0', 'teacher01', '2026-03-20 10:00:00', '', '2026-03-20 10:00:00', '0', '4', '1'),
('101', '新工科背景下软件工程专业人才培养模式探索与实践', '<p>面向新工科建设需求，本项目围绕"厚基础、宽口径、重实践、求创新"的人才培养理念，对软件工程专业课程体系进行了系统性重构。核心举措包括：增设人工智能导论、大数据技术基础、云计算与边缘计算等前沿课程模块；建立"基础实验-综合实训-企业实习"三层次实践教学体系；引入华为、腾讯等企业认证课程，实现课证融通。</p><p>经过两年的教学实践，专业毕业生一次就业率从86%提升至94%，应届生平均薪资增长18%，用人单位满意度达到96.5%。2025年软件工程专业通过教育部工程教育认证。</p>', '', '201', '111', '2', 'teacher02', '2026-03-25 14:30:00', '', '2026-04-15 09:00:00', '0', '4', '2'),
('102', '《面向对象程序设计》课程思政教学设计与实施', '<p>本项目将课程思政理念有机融入《面向对象程序设计》课程教学全过程。在讲授类与对象、继承与多态、设计模式等核心知识点时，通过精心设计的教学案例引导学生理解"模块化思维与团队协作"、"代码规范与职业操守"、"开源精神与社会责任"等思政元素。</p><p>项目团队开发了12个课程思政教学案例库，涵盖工匠精神、科技报国、信息安全法规等主题。课程获评校级课程思政示范课程，学生课程满意度从82%提升至95%。相关教学成果在校内16个专业推广，累计受益学生超过2000人。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '200', '111', '3', 'teacher01', '2026-04-01 09:00:00', 'schoolAudit', '2026-04-18 16:30:00', '0', '1', '2'),
('103', '校企协同共建软件测试实践教学平台', '<p>本项目联合中软国际、博彦科技两家知名IT企业，共建了面向本科生的软件测试实践教学平台。平台涵盖单元测试、集成测试、性能测试、安全测试和自动化测试五大模块，集成了JUnit、Selenium、JMeter、SonarQube等主流测试工具链，支持超过40个实训项目。</p><p>平台投入使用一年来，累计支撑了《软件测试》《软件质量保证》等4门课程的教学，实验开出率达到100%。学生参与企业真实项目的比例从10%提升至55%，多名学生获得ISTQB国际软件测试工程师认证。2025年学生在"全国大学生软件测试大赛"中获国家级一等奖1项、二等奖2项。</p>', '', '201', '111', '3', 'teacher02', '2026-03-28 11:00:00', 'schoolAudit', '2026-04-16 10:00:00', '0', '3', '1'),
('104', '基于OBE理念的软件项目管理课程考核方式改革', '<p>针对《软件项目管理》课程传统闭卷考试难以考查学生实际项目管理能力的痛点，本项目引入了基于OBE（成果导向教育）理念的多元化考核方式。将课程考核分为：过程性评价（40%，包括课堂参与、小组讨论、周报撰写）、项目实战（40%，以5-6人小组完成一个完整的软件开发项目）、期末答辩（20%，展示项目成果并进行同行评审）。</p><p>改革实施两个学期后，学生项目文档规范率从58%提升至89%，团队协作能力显著增强。然而项目组在实施过程中也面临小组分工不均衡、评分标准主观性等问题，尚需进一步完善评价量规。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '200', '111', '2', 'teacher01', '2026-04-10 15:00:00', '', '2026-04-12 08:30:00', '0', '5', '3'),
('105', '面向大数据方向的软件工程课程体系建设方案', '<p>本项目旨在构建面向大数据方向的软件工程特色课程体系，计划在现有软件工程专业课程基础上，增设《数据采集与预处理》《分布式计算框架》《数据可视化技术》《机器学习应用开发》四门核心课程，形成大数据方向课程群。同步规划建设大数据实验中心，配备Hadoop/Spark集群和GPU计算资源。</p><p>该方案经学院教学指导委员会审议后被驳回，主要原因是：现有实验条件暂时无法支撑大规模数据处理实验，且师资力量在数据科学领域储备不足。建议先行培养师资并完成基础设施建设后重新申报。</p>', '', '202', '111', '4', 'teacher03', '2026-04-05 10:00:00', 'schoolAudit', '2026-04-20 14:00:00', '0', '4', '3');
INSERT INTO `edu_achievement` VALUES
('106', '以学生为中心的混合式教学模式创新——以《计算机网络》为例', '<p>本项目探索了基于"线上+线下"混合式教学模式的《计算机网络》课程改革。线上部分依托超星学习通平台，建设了包含68个微课视频、200余道在线习题、15个虚拟仿真实验的教学资源库；线下课堂采用翻转课堂模式，重点进行疑难解答、案例研讨和项目汇报。</p><p>项目实践3个学期以来，学生的期末平均成绩从72.3分提升至81.5分，不及格率从15%降至6%。学生自主学习能力明显增强，课前视频观看率达到92%。项目成果已发表教学研究论文2篇，获省级教学成果二等奖。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '203', '109', '3', 'teacher04', '2026-03-15 09:00:00', 'schoolAudit', '2026-04-12 15:00:00', '0', '6', '2'),
('107', '基于大语言模型的编程课程智能助教系统研发', '<p>本项目利用通用大语言模型技术，开发了面向《C语言程序设计》和《Python程序设计》课程的智能助教系统。系统具备以下功能：（1）代码自动批改：对学生的编程作业进行语法检查和逻辑审查，生成评分和修改建议；（2）个性化答疑：基于课程知识库，回答学生提出的编程问题；（3）学习路径推荐：根据学生的学习数据，推荐针对性的练习题和视频资源。</p><p>系统于2026年春季学期在5个教学班试用，累计批改代码作业1200余份，教师批改工作量降低约40%。学生对系统的满意度为88%，普遍认为即时反馈对编程学习非常有帮助。但同时发现系统对复杂算法的评分准确性仍有提升空间。</p>', '', '204', '109', '2', 'teacher05', '2026-04-15 10:00:00', '', '2026-04-16 09:00:00', '0', '1', '0'),
('108', '校企协同共建人工智能实践教学平台', '<p>本项目联合科大讯飞、商汤科技两家AI企业，共建了面向本科生的人工智能实践教学平台。平台集成了数据标注、模型训练、模型评估与部署等全流程工具链，提供超过30个实训项目，涵盖计算机视觉、自然语言处理、语音识别三大方向。平台采用容器化部署，学生通过浏览器即可访问完整的GPU开发环境。</p><p>平台投入使用后，AI相关课程的实验开出率达到100%，学生参与企业真实项目的比例从15%提升至60%。依托平台孵化了3个大学生创新创业项目，其中"基于深度学习的校园安防系统"获省级优秀大创项目。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '203', '109', '3', 'teacher04', '2026-03-18 10:00:00', 'schoolAudit', '2026-04-14 09:00:00', '0', '3', '2'),
('109', '新工科背景下物联网工程专业实践教学体系构建', '<p>面向物联网工程专业实践教学需求，构建了"基础感知→网络传输→数据处理→应用开发"四层递进的实践教学体系。每一层设置对应的实验课程和实训项目：基础感知层包括传感器数据采集、嵌入式系统编程等6个项目；网络传输层包括WiFi/蓝牙/ZigBee组网实验等8个项目；数据处理层包括时序数据库操作、边缘计算节点部署等5个项目；应用开发层包括智能家居、智慧农业等综合实训项目。</p><p>该体系已连续实施3个学期，累计覆盖学生360人。学生的工程实践能力和系统集成能力显著提升，在全国大学生物联网设计竞赛中获国家级二等奖1项、三等奖2项。</p>', '', '204', '109', '3', 'teacher05', '2026-03-22 14:00:00', 'schoolAudit', '2026-04-17 11:00:00', '0', '3', '3'),
('110', '《数据结构》课程教学改革与实践', '<p>本项目针对《数据结构》课程"概念抽象、算法难懂"的教学难点，采用可视化教学和项目驱动相结合的教学方法。利用开源可视化工具（如VisuAlgo、Algorithm Visualizer）将抽象的数据结构和算法过程直观呈现给学生，同时设计了"校园导航系统"、"公交线路优化"等贴近生活的课程项目，让学生在解决实际问题中理解数据结构的应用价值。</p><p>经过两个学期的教学实践，学生在期末考试中算法设计题的平均得分提高20%。然而项目因教学评价指标设计不够完善，同行评审认为缺少与同类型课程的可比性数据，未能通过校级审核。</p>', '', '205', '109', '4', 'teacher06', '2026-04-08 09:00:00', 'schoolAudit', '2026-04-22 16:00:00', '0', '6', '3'),
('111', '计算机类课程"竞赛驱动"教学模式研究', '<p>本项目探索将学科竞赛融入日常教学的"竞赛驱动"模式。选取ACM程序设计竞赛、蓝桥杯全国软件和信息技术专业人才大赛、中国大学生计算机设计大赛等高水平赛事内容，拆解为课堂教学案例和课后训练任务。通过"课堂讲授—训练巩固—校内选拔—省赛国赛"四阶段递进，激发学生的学习动力和创新潜能。</p><p>实施两年来，学生参与学科竞赛的覆盖面从15%提升至45%，在蓝桥杯、ACM等赛事中累计获国家级奖项8项、省级奖项22项。目前该成果已提交校级审核，等待最终评审结果。</p>', '', '203', '109', '2', 'teacher04', '2026-04-18 16:00:00', '', null, '0', '3', '2');
INSERT INTO `edu_achievement` VALUES
('112', '基于虚拟仿真技术的电力系统实验教学改革', '<p>本项目针对电力系统实验存在的高电压危险、设备昂贵、故障模拟困难等问题，利用MATLAB/Simulink和ETAP电力系统仿真软件，开发了涵盖发电、输电、变电、配电全过程的虚拟仿真实验平台。平台包含潮流计算、短路故障分析、继电保护整定、新能源并网等12个仿真实验项目。</p><p>虚拟仿真平台与真实物理实验互补，学生在虚拟环境中可以安全地模拟各种故障工况，加深对电力系统运行原理的理解。项目实施后，学生实验报告质量显著提升，在全国大学生电气设计竞赛中获省级一等奖1项。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '206', '101', '3', 'teacher07', '2026-03-20 08:00:00', 'schoolAudit', '2026-04-15 10:00:00', '0', '3', '3'),
('113', '电气工程专业课程思政一体化建设方案', '<p>本项目系统构建了电气工程专业"课程思政一体化"教学体系，从专业导论课到毕业设计，将思政教育贯穿培养全过程。在《电路原理》中融入"基尔霍夫"等科学家的科研精神；在《电机学》中讲述中国高铁牵引电机的自主创新历程；在《电力系统分析》中探讨"西电东送"等国家战略工程。</p><p>项目成果已形成课程思政案例集（共计28个教学案例）和教学指导手册。经过一个完整培养周期的实践，学生对中国电力工业发展的认同感和自豪感明显增强。目前该成果已提交审核。</p>', '', '207', '101', '2', 'teacher08', '2026-04-12 09:00:00', '', null, '0', '1', '1'),
('114', 'OBE理念下自动化专业课程考核体系重构', '<p>本项目以成果导向教育（OBE）理念为指导，对自动化专业的课程考核体系进行了全面重构。核心措施包括：（1）建立"课程目标—毕业要求—考核方式"三级映射矩阵，确保每项考核都能有效测量相应的能力指标；（2）引入多元化的考核形式，包括课堂测验、实验报告、项目答辩、企业实习评价、电子作品集等；（3）开发了基于Web的课程达成度自动计算系统。</p><p>经过一个学年的运行，课程目标达成度评价的效率提升了60%，教学持续改进有了数据支撑。但部分教师反映新体系的工作量较大，需要进一步简化和优化评价流程。</p>', '', '208', '101', '0', 'teacher09', '2026-04-20 14:00:00', '', '2026-04-22 09:00:00', '0', '5', '4'),
('115', '校企合作培养电气工程应用型人才的实践与思考', '<p>本项目与许继集团、平高电气等6家电力行业龙头企业建立了深度合作关系，构建了"3+1"应用型人才培养模式（3年校内学习+1年企业实践）。校企双方共同制定培养方案、开发课程资源、指导学生毕业设计。学生在企业实习期间直接参与智能变电站调试、新能源发电项目等真实工程项目。</p><p>项目实施以来，累计有120名学生进入合作企业实习，其中45人毕业后直接留任合作企业。毕业生工程实践能力得到用人单位高度认可，就业专业对口率从72%提升至91%。该成果已通过校级审核。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '206', '101', '3', 'teacher07', '2026-03-25 10:00:00', 'schoolAudit', '2026-04-18 08:00:00', '0', '2', '2'),
('116', '基于项目驱动的嵌入式系统课程教学改革', '<p>本项目将Arduino和STM32单片机引入《嵌入式系统》课程教学，采用项目驱动方式组织教学内容。课程设置"智能温控风扇"、"蓝牙遥控小车"、"物联网环境监测站"等8个由浅入深的课程项目，每个项目融合了硬件设计、软件开发、系统调试等多方面技能训练。</p><p>根据学院审核反馈，该方案在技术选型上偏重Arduino平台，对工业级嵌入式开发（如ARM Cortex-M系列）涉及不足，与行业需求存在一定差距，被驳回修改。</p>', '', '207', '101', '4', 'teacher08', '2026-04-14 09:00:00', 'schoolAudit', '2026-04-23 15:00:00', '0', '3', '3');
INSERT INTO `edu_achievement` VALUES
('117', '以学生为中心的混合式教学在大学英语中的应用', '<p>本项目探索了基于"线上+线下"混合式教学模式的大学英语课程改革。通过建设MOOC资源库、搭建智能学习分析平台，实现了个性化学习路径推荐和精准教学干预。线上资源包括120个微课视频（涵盖听、说、读、写、译五项技能）、500余道自适应练习题库和AI口语陪练模块。</p><p>项目实践3个学期以来，学生的CET-4通过率从72%提升至89%，学习满意度和课堂参与度均有显著提升。特别是在口语表达能力方面，学生PTE口语平均分提高12%。项目成果已发表教学研究论文2篇，获得省级教学成果二等奖。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '209', '115', '3', 'teacher10', '2026-03-18 08:00:00', 'schoolAudit', '2026-04-14 14:00:00', '0', '6', '2'),
('118', '外语专业"课程思政"教学改革路径探索', '<p>本项目在外语专业课程中系统融入课程思政教育，通过"语言教学+文化对比+价值引领"三维教学模式，培养具有家国情怀和国际视野的外语人才。在《综合英语》课程中，增加中国传统文化英文译介、当代中国发展成就英文报道等教学内容；在《翻译理论与实践》课程中，选取"一带一路"、乡村振兴等国家战略相关材料进行翻译训练。</p><p>实践表明，学生在提升语言能力的同时，对中国文化和国家发展的理解更为深入。学生在全国大学生英语竞赛中获特等奖1项、一等奖3项。目前该成果已提交校级审核。</p>', '', '210', '115', '2', 'teacher11', '2026-04-10 10:00:00', '', null, '0', '1', '1'),
('119', '基于AI技术的外语写作智能反馈系统设计与应用', '<p>本项目开发了一款基于自然语言处理技术的外语写作智能反馈系统。系统能够对学生的英语作文进行语法错误检测、词汇丰富度分析、篇章结构评估和逻辑连贯性检验，并生成详细的修改建议报告。系统内置CEFR（欧洲语言共同参考框架）评分标准，可为不同水平的学生提供差异化反馈。</p><p>系统在3个教学班试用一学期后，学生作文修改次数平均增加2.3次，写作成绩提升显著。然而系统在语义理解和论证逻辑评估方面存在局限，部分反馈建议的准确性有待提高，该项目尚处于草稿阶段，计划进一步完善后提交审核。</p>', '', '211', '115', '0', 'teacher12', '2026-04-22 15:00:00', '', '2026-04-23 09:00:00', '0', '4', '0'),
('120', '校企协同培养跨境电商复合型外语人才', '<p>本项目联合阿里巴巴国际站、亚马逊全球开店等跨境电商平台，构建了"外语+电商+国际商务"复合型人才培养模式。课程体系新增《跨境电商英语》《国际商务谈判》《外贸函电与单证》等专业方向课程，并在企业导师指导下完成跨境电商店铺运营实战项目。学生在实训期间需完成产品上架、英文文案撰写、客户沟通、订单处理等全流程操作。</p><p>项目已培养两届毕业生共计86人，其中78%从事跨境电商相关工作，用人单位普遍反馈学生外语应用能力和商务实践能力突出。该成果已通过校级审核。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '209', '115', '3', 'teacher10', '2026-04-02 09:00:00', 'schoolAudit', '2026-04-19 10:00:00', '0', '2', '3'),
('121', '过程性评价在外语教学中的应用研究', '<p>本项目改革了传统以期末考试为主的评价方式，构建了外语课程全过程多元评价体系。评价维度包括：课堂表现（15%）、线上学习数据（15%）、小组项目（20%）、阶段性测试（20%）、期末综合测试（30%）。利用学习通平台自动采集学生学习行为数据，为过程性评价提供客观依据。</p><p>项目经过两个学期的试点实践，学生课堂参与度和学习主动性显著提升，期末成绩分布更加合理。评审专家认为该评价体系设计科学、操作性强，具有较高的推广价值。该成果已通过校级审核。</p>', '', '210', '115', '3', 'teacher11', '2026-04-16 10:00:00', 'schoolAudit', '2026-04-24 11:00:00', '0', '5', '2');
INSERT INTO `edu_achievement` VALUES
('122', '基于案例教学法的工商管理专业实践教学改革', '<p>本项目以案例教学法为核心，对工商管理专业实践教学体系进行了系统改革。教学团队自主开发了30个本土化企业管理教学案例，涵盖战略管理、市场营销、人力资源、财务管理等核心领域。案例素材来源于河南省本地知名企业（如宇通客车、双汇集团、三全食品等）的真实管理实践。</p><p>教学过程采用"个人研读—小组讨论—课堂展示—教师点评"四步案例教学法。实施两年来，学生在"全国管理决策模拟大赛"中获国家级一等奖1项，学生综合分析能力和决策能力显著提升。该成果已通过校级审核。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '212', '108', '3', 'teacher13', '2026-03-20 09:00:00', 'schoolAudit', '2026-04-16 08:00:00', '0', '2', '2'),
('123', '大数据驱动的市场营销课程教学创新', '<p>本项目将大数据分析技术引入市场营销课程教学，培养学生数据驱动的营销决策能力。课程新增《Python数据采集与分析》《营销数据分析与可视化》《用户画像与精准营销》等数据营销模块，并与本地电商企业合作，为学生提供真实的用户行为数据用于课堂实训。</p><p>学生通过课程掌握了Python爬虫、数据清洗、RFM模型分析、Tableau可视化等实用技能。目前已提交审核，等待评审结果。</p>', '', '213', '108', '2', 'teacher14', '2026-04-12 14:00:00', '', null, '0', '4', '1'),
('124', 'OBE理念下《管理学原理》课程教学改革实践', '<p>本项目基于OBE理念，对《管理学原理》课程进行了全面改革。明确了"知识理解、能力养成、素质提升"三个层次的课程目标，并围绕目标设计了：翻转课堂研讨（20%）、管理情景模拟（30%）、企业实地调研（25%）、期末考试（25%）的多元化教学与考核方案。特别是管理情景模拟环节，学生在模拟公司中担任CEO、CFO等角色，完成季度经营决策。</p><p>课程改革后，学生课堂参与度从65%提升至90%，在"学创杯"全国大学生创业综合模拟大赛中获省级一等奖。目前该成果已提交审核。</p>', '', '214', '108', '2', 'teacher15', '2026-04-10 08:00:00', '', '2026-04-11 10:00:00', '0', '6', '1'),
('125', '经济学专业课程思政教学改革探索', '<p>本项目在经济学专业课程中系统开展课程思政教学改革。在《微观经济学》中讲述中国市场经济改革历程，培养学生对社会主义市场经济的制度自信；在《宏观经济学》中分析中国经济增长奇迹背后的制度优势；在《发展经济学》中介绍中国脱贫攻坚的伟大实践。</p><p>项目团队编写了《经济学课程思政教学指南》，包含15个专题教学设计和配套案例。该成果已通过校级审核，并在校内多个经管类专业推广应用。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '212', '108', '3', 'teacher13', '2026-04-05 09:00:00', 'schoolAudit', '2026-04-21 10:00:00', '0', '1', '3'),
('126', '经管类虚拟仿真实验教学平台建设', '<p>本项目规划建设经管类虚拟仿真实验教学平台，拟采用用友新道VBSE（虚拟商业社会环境）平台，构建涵盖制造企业、商贸企业、银行、税务、物流公司等多元主体的仿真商业环境。学生在平台中可进行企业经营管理全流程仿真操作，包括生产计划、采购管理、市场营销、财务核算、税务申报等业务环节。</p><p>该方案目前处于草稿阶段，有待进一步论证平台经费预算和技术实施方案的可行性。</p>', '', '213', '108', '0', 'teacher14', '2026-04-23 16:00:00', '', null, '0', '3', '4');
INSERT INTO `edu_achievement` VALUES
('127', '基于Python的信息与计算科学专业实践课程改革', '<p>本项目将Python编程语言全面引入信息与计算科学专业的实践课程体系。将传统的MATLAB/C语言实践环节替换为Python，利用NumPy、SciPy、Matplotlib、Pandas等科学计算库重新设计了数值分析、数学建模、数据挖掘等课程的实验内容。同时，在课程中加入Jupyter Notebook交互式编程环境，提升学生的编程效率和数据分析体验。</p><p>项目实施后，学生在各类数学建模竞赛中的编程环节得分显著提升，在全国大学生数学建模竞赛中获国家级一等奖2项、二等奖4项。该成果已通过校级审核。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf', '215', '116', '3', 'teacher16', '2026-03-18 10:00:00', 'schoolAudit', '2026-04-13 09:00:00', '0', '4', '1'),
('128', '数学建模竞赛驱动的创新人才培养模式', '<p>本项目构建了以数学建模竞赛为载体的创新人才培养模式。建立了"通识选修→建模培训→校内选拔→赛前集训→国赛参赛"五阶段培养链条，组建了由数学、计算机、经管等学科教师组成的跨学科指导团队。每年面向全校开设《数学建模》通识选修课，覆盖学生300余人；从中选拔优秀学生进入集训队，开展为期6周的集中训练。</p><p>该模式实施三年来，学校在全国大学生数学建模竞赛中的获奖数量逐年递增，2025年获国家级一等奖3项、二等奖6项，位列全省高校前列。该成果已通过校级审核。</p>', '', '216', '116', '3', 'teacher17', '2026-03-15 09:00:00', 'schoolAudit', '2026-04-12 11:00:00', '0', '3', '0'),
('129', '《高等数学》分层教学改革方案', '<p>本项目针对学生数学基础差异较大的现状，提出了《高等数学》分层教学改革方案。按学生入学数学成绩和专业需求将教学班级分为A（提高层）、B（标准层）、C（基础层）三个层次，分别制定差异化的教学大纲、教学进度和考核标准。A层增加数学证明和拓展内容，培养数学研究兴趣；B层按照教学大纲正常教学；C层强化基础训练，增加习题课和辅导答疑。</p><p>方案已提交校级审核，目前等待评审结果。</p>', '', '217', '116', '2', 'teacher18', '2026-04-15 09:00:00', '', null, '0', '5', '2'),
('130', '大数据技术在统计学教学中的应用探索', '<p>本项目将大数据分析技术引入统计学课程教学，更新了传统统计学以手工计算和小样本分析为主的教学内容。新增"Python统计分析"、"数据可视化与探索性数据分析"、"机器学习与统计学习"三个实践模块，使用真实数据集（如城市空气质量数据、电商用户行为数据）进行课堂实训，让学生在实践中理解统计方法的实际应用价值。</p><p>课程改革后，学生对统计学的学习兴趣明显提升，统计软件操作技能得到有效训练。该成果已通过校级审核。</p>', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '215', '116', '3', 'teacher16', '2026-04-08 10:00:00', 'schoolAudit', '2026-04-22 08:00:00', '0', '6', '3'),
('131', '计算数学课程群教学改革探索', '<p>本项目针对计算数学方向的核心课程群（数值分析、数学物理方程、最优化方法）进行一体化教学改革。设计了课程群统一的教学案例库，以工程问题为驱动，打通课程间的知识壁垒。例如，设置"桥梁结构应力分析"项目，综合运用数值分析（有限元方法）、数学物理方程（偏微分方程建模）、最优化方法（结构优化设计）三方面的知识。</p><p>该项目因涉及课程较多、协调难度大，且部分教师对课程群改革存在不同意见，经专家评审后予以驳回。建议先以小范围试点方式推进，积累经验后再申请全面改革。</p>', '', '216', '116', '4', 'teacher17', '2026-04-18 10:00:00', 'schoolAudit', '2026-04-25 09:00:00', '0', '4', '2');
INSERT INTO `edu_news` VALUES
('30', '关于2026年春季学期期中教学检查的通知', '教务处将于第8-9周组织开展春季学期期中教学检查工作，重点检查课堂教学质量、实践教学环节和教学档案管理情况。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各教学单位：</p><p>为进一步规范教学管理，全面了解本学期教学运行状况，及时发现和解决教学过程中存在的问题，根据学校教学工作安排，决定于第8-9周（4月20日-4月30日）开展2026年春季学期期中教学检查工作。现将有关事项通知如下：</p><p>一、检查内容：课堂教学质量（包括教师到岗、学生到课、课堂教学组织等）、实践教学环节（包括实验、实习、课程设计等）、教学档案管理（包括教学日历、教案、作业批改等）。</p><p>二、检查方式：采取学院自查与学校抽查相结合的方式进行。各学院于4月23日前完成自查并提交自查报告，学校检查组将于4月26-30日进行随机抽查。</p><p>三、工作要求：请各学院高度重视本次期中教学检查工作，认真组织，实事求是地查找问题，制定整改措施。</p>', '2026-04-18 08:30:00', '320', '1', '100', '0', '1', 'admin', '2026-04-18 08:30:00', '', '2026-04-18 08:30:00', '0'),
('31', '关于开展教师教学能力提升培训的通知', '教务处将于5月举办"教学创新与信息化教学能力提升"系列培训，邀请校内外专家开展专题讲座和工作坊。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各位教师：</p><p>为持续提升我校教师教学能力和专业素养，推动信息技术与教育教学深度融合，教务处拟于2026年5月举办"教学创新与信息化教学能力提升"系列培训活动。具体安排如下：</p><p>一、培训时间：2026年5月6日-5月27日，每周三、周五下午14:30-17:00。</p><p>二、培训内容：教学创新大赛经验分享、混合式教学设计工作坊、AI辅助教学工具使用培训、一流课程申报指导等。</p><p>三、培训对象：全校在职教师均可报名参加，鼓励中青年教师和新入职教师积极参加。</p><p>四、报名方式：请于4月30日前登录教师发展中心系统在线报名。</p>', '2026-04-22 10:00:00', '185', '1', '100', '0', '1', 'admin', '2026-04-22 10:00:00', '', '2026-04-22 10:00:00', '0'),
('32', '关于提交省级教学成果奖申报材料的紧急通知', '请各学院于4月28日下班前将2026年度省级教学成果奖申报材料报送至教务处教学研究科，逾期不予受理。', '', '<p>各学院：</p><p>根据河南省教育厅《关于开展2026年度河南省高等教育省级教学成果奖评选工作的通知》要求，学校现组织省级教学成果奖申报推荐工作。有关事项紧急通知如下：</p><p>一、申报范围：已获得2024-2025学年校级教学成果一等奖及以上的成果。</p><p>二、申报材料：（1）《河南省高等教育省级教学成果奖申报书》（一式三份）；（2）成果总结报告（不超过5000字）；（3）支撑材料（含成果应用效果证明、公开发表的论文等）。</p><p>三、时间节点：请各学院于4月28日（周二）17:00前将申报材料电子版和纸质版报送至教务处教学研究科（办公楼302室）。逾期不予受理，请务必按时提交。</p><p>联系人：张老师，电话：0371-8660XXXX</p>', '2026-04-25 15:00:00', '472', '1', '100', '0', '1', 'admin', '2026-04-25 15:00:00', '', '2026-04-25 15:00:00', '0'),
('33', '2026届毕业设计中期检查工作安排', '教务处将于5月上旬对2026届本科毕业设计（论文）工作进行中期检查，重点检查指导教师履职和进展情况。', '', '<p>各学院：</p><p>为加强本科毕业设计（论文）过程管理，确保毕业设计工作质量，根据《郑州轻工业大学本科毕业设计（论文）管理办法》，决定对2026届本科毕业设计（论文）进行中期检查。具体安排如下：</p><p>一、检查时间：2026年5月6日-5月15日。</p><p>二、检查内容：指导教师履职情况、学生毕业设计（论文）进展、开题报告质量、外文翻译完成情况等。</p><p>三、检查方式：各学院成立中期检查小组，采取学生汇报、查阅材料、座谈交流等方式开展检查。学校将组织专家组进行抽查。</p><p>四、材料报送：各学院于5月18日前将中期检查总结报告报送教务处实践教学科。</p>', '2026-04-24 09:00:00', '256', '1', '100', '0', '1', 'admin', '2026-04-24 09:00:00', '', '2026-04-24 09:00:00', '0'),
('34', '关于推荐优秀教学成果参加全国展示的通知', '教育部将于6月举办全国高校教学成果展，现面向全校征集优秀教学成果参展项目，请各单位积极推荐。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各单位：</p><p>根据教育部高等教育司通知，2026年度全国高校教学成果展定于6月15-17日在北京国家会议中心举办。为充分展示我校教育教学改革成果，现面向全校征集参展项目。具体要求如下：</p><p>一、征集范围：近三年获得校级及以上教学成果奖的项目，或在教学改革中取得突出成效的成果。</p><p>二、推荐名额：每个学院可推荐1-2项优秀成果。</p><p>三、参展形式：实物展板、视频展示、互动演示等。</p><p>四、时间安排：请各学院于5月10日前将推荐项目汇总表及展示材料初稿提交至教务处。</p>', '2026-04-20 14:00:00', '198', '1', '100', '0', '1', 'admin', '2026-04-20 14:00:00', '', '2026-04-20 14:00:00', '0'),
('35', '关于2026年度校级教学成果奖申报工作的通知', '2026年度校级教学成果奖申报工作即日启动，请各单位组织教师按时通过教学成果管理平台在线提交材料。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各单位：</p><p>根据学校工作安排，2026年度校级教学成果奖申报工作即日启动。现将有关事项通知如下：</p><p>一、申报范围：全校在职教师及教学管理人员，申报成果应为近4年（2022年9月至2026年4月）取得的教学成果。</p><p>二、申报时间：即日起至2026年5月31日。</p><p>三、申报方式：登录教学成果管理平台，在线填写申报信息并上传相关证明材料。</p><p>四、奖项设置：设特等奖、一等奖、二等奖三个等级，获奖成果将择优推荐申报省级教学成果奖。</p>', '2026-04-15 08:00:00', '385', '1', '100', '0', '1', 'admin', '2026-04-15 08:00:00', '', '2026-04-15 08:00:00', '0'),
('36', '关于调整教学成果校级审核评分细则的通知', '为进一步规范教学成果审核流程，教务处对校级审核评分标准进行了优化调整，增加了创新性权重和推广应用效果维度。', '', '<p>各学院及校级审核员：</p><p>为提升教学成果审核的规范性与公正性，教务处在广泛征求意见的基础上，对校级审核评分细则进行了以下优化调整：</p><p>一、调整创新性权重，由原15%提升至25%，鼓励教师在教学理念、教学模式、教学方法等方面进行原创性探索。</p><p>二、新增"推广应用效果"评估维度（权重15%），考察成果在校内外推广应用的范围和实际效果。</p><p>三、细化教学改革类成果的评价指标，增设"理论支撑"、"方案设计"、"实施过程"、"效果评价"四个二级指标。</p><p>四、新评分细则自2026年5月1日起施行，届时教学成果管理平台将同步更新评分模板。</p>', '2026-04-12 10:00:00', '310', '1', '100', '0', '1', 'admin', '2026-04-12 10:00:00', '', '2026-04-12 10:00:00', '0'),
('37', '关于2026年度教学改革研究项目立项申报的通知', '学校启动2026年度校级教学改革研究项目立项申报工作，设重点项目和一般项目两个类别。', '', '<p>各学院、各单位：</p><p>为深化教育教学改革，鼓励教师积极开展教学研究，学校决定开展2026年度校级教学改革研究项目立项申报工作。有关事项通知如下：</p><p>一、项目类别：设重点项目（资助3万元/项）和一般项目（资助1万元/项）。</p><p>二、申报方向：课程思政建设、一流课程建设、实践教学改革、创新创业教育、教学质量保障等。</p><p>三、申报条件：项目负责人须具有中级及以上职称，原则上在研校级教改项目不超过1项。</p><p>四、申报截止时间：2026年5月20日。</p>', '2026-04-08 09:00:00', '278', '1', '100', '0', '1', 'admin', '2026-04-08 09:00:00', '', '2026-04-08 09:00:00', '0'),
('38', '关于公布2025-2026学年第二学期教学督导工作安排的通知', '学校教学督导委员会发布了本学期教学督导工作计划，将开展常规听课评课和专项教学质量检查。', '', '<p>各教学单位：</p><p>为加强教学质量监控，促进教师教学能力提升，学校教学督导委员会制定了2025-2026学年第二学期教学督导工作计划。现将有关安排公布如下：</p><p>一、常规听课评课：校级督导专家本学期计划听课评课不少于60节次，覆盖各学院青年教师和新开课程。</p><p>二、专项检查：重点开展"混合式教学实施情况"和"课程思政建设情况"两项专项检查。</p><p>三、教学沙龙：每月举办1次教学沙龙活动，邀请优秀教师分享教学经验。</p><p>四、反馈机制：督导意见将通过教务系统及时反馈给教师本人和所在学院。</p>', '2026-03-25 14:00:00', '145', '1', '100', '0', '1', 'admin', '2026-03-25 14:00:00', '', '2026-03-25 14:00:00', '0'),
('39', '关于教学成果管理平台使用培训的通知', '教务处将于4月举办两场教学成果管理平台操作培训，帮助教师熟练使用平台进行成果申报和审核。', '', '<p>各学院、各位教师：</p><p>为帮助各位教师和审核人员熟练掌握新版教学成果管理平台的操作，教务处拟举办两场线上培训。具体安排如下：</p><p>一、第一场（教师专场）：4月28日（周二）14:30-16:00，培训内容：成果申报、材料上传、进度查询、驳回修改等操作。</p><p>二、第二场（审核员专场）：4月29日（周三）14:30-16:00，培训内容：审核流程操作、评分表填写、审核意见撰写规范。</p><p>三、培训方式：通过腾讯会议线上进行（会议号另行通知），同时录制视频上传至平台供回看。</p><p>四、参加人员：请各学院教学秘书、拟申报成果的教师及相关审核人员务必参加。</p>', '2026-04-25 09:00:00', '110', '1', '100', '0', '1', 'admin', '2026-04-25 09:00:00', '', '2026-04-25 09:00:00', '0');
INSERT INTO `edu_news` VALUES
('40', '我校成功举办2026年教学创新大赛', '4月20日，郑州轻工业大学2026年教学创新大赛决赛在科学校区学术报告厅举行，来自各学院的18位教师参加了决赛展示。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>4月20日，郑州轻工业大学2026年教学创新大赛决赛在科学校区学术报告厅隆重举行。本次大赛以"创新教学、提质增效"为主题，经各学院初赛推荐，共有18位教师进入校级决赛。</p><p>比赛分为教学设计汇报和现场授课展示两个环节。参赛教师围绕课程思政融入、混合式教学设计、项目驱动教学、虚拟仿真实验等主题进行了精彩展示，充分体现了我校教师在教学改革与创新方面的积极探索。</p><p>经评委评审，软件学院张伟老师、外国语学院孙悦老师荣获一等奖；另有3位教师获二等奖，5位教师获三等奖。校领导为获奖教师颁奖，并鼓励全体教师以赛促教、以赛促改，不断提升教学水平。</p>', '2026-04-21 16:00:00', '430', '1', '90', '0', '2', 'admin', '2026-04-21 16:00:00', '', '2026-04-21 16:00:00', '0'),
('41', '计算机学院获批国家一流本科专业建设点', '我校计算机科学与技术专业成功入选2025年度国家级一流本科专业建设点，标志着我校计算机类专业建设迈上新台阶。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，教育部办公厅公布了2025年度国家级一流本科专业建设点名单，我校计算机科学与技术专业成功入选。这是继食品科学与工程、高分子材料与工程之后，我校获批的第三个国家级一流本科专业建设点。</p><p>计算机科学与技术专业始建于1994年，经过三十余年的建设发展，已经形成了较为完善的"基础理论+工程实践+创新训练"人才培养体系。该专业近年来在课程建设、教材建设、实验室建设等方面取得了显著成绩，学生在ACM程序设计竞赛、中国大学生计算机设计大赛等赛事中屡获佳绩。</p><p>学院负责人表示，将以国家级一流专业建设为契机，进一步深化教育教学改革，努力培养更多高素质计算机专业人才。</p>', '2026-03-20 10:00:00', '486', '1', '85', '0', '2', 'admin', '2026-03-20 10:00:00', '', '2026-03-20 10:00:00', '0'),
('42', '软件学院校企合作成果入选教育部典型案例', '我校软件学院与中软国际联合建设的"产教融合软件人才培养基地"成功入选教育部2025年产教融合校企合作典型案例。', '', '<p>近日，教育部高等教育司公布了2025年度产教融合校企合作典型案例名单，我校软件学院与中软国际联合建设的"产教融合软件人才培养基地"成功入选，全国共有100个案例获此殊荣。</p><p>该基地自2023年启动建设以来，校企双方在人才培养方案制定、课程资源开发、双师型教师培养、学生实习实训等方面开展了全方位合作。已联合开发校企合作课程12门，共建实验室3个，企业工程师进校授课累计超过1000学时。三年来，基地累计培养软件工程专业学生600余名，毕业生一次就业率保持在94%以上。</p><p>软件学院院长表示，此次入选教育部典型案例是对学校产教融合工作的充分肯定，学院将继续深化校企合作内涵，探索更多产教融合新模式。</p>', '2026-03-05 09:00:00', '295', '1', '80', '0', '2', 'admin', '2026-03-05 09:00:00', '', '2026-03-05 09:00:00', '0'),
('43', '我校教师在省级教学竞赛中荣获一等奖', '在2026年河南省本科高校教师课堂教学创新大赛中，我校电气信息工程学院周鹏老师荣获理工组一等奖。', '', '<p>近日，由河南省教育厅主办的2026年河南省本科高校教师课堂教学创新大赛圆满落幕。经过激烈角逐，我校电气信息工程学院周鹏老师凭借"电力系统分析"课程精彩的课堂展示和创新的教学设计，荣获理工组一等奖；外国语学院孙悦老师获文科组二等奖。</p><p>本次大赛共有来自全省56所本科高校的180余名教师参赛。周鹏老师在比赛中展示了其独创的"工程案例导入+仿真软件辅助+小组探究研讨"三段式教学模式，将抽象的电力系统概念通过工程实例和仿真可视化生动呈现。</p><p>教务处负责人表示，学校将以此次获奖为契机，进一步推动课堂教学改革，鼓励更多教师投身教学创新实践。</p>', '2026-04-03 15:00:00', '378', '1', '75', '0', '2', 'admin', '2026-04-03 15:00:00', '', '2026-04-03 15:00:00', '0'),
('44', '外国语学院探索"AI+外语"教学新模式', '外国语学院举办"AI赋能外语教学"专题研讨会，探讨人工智能技术在语言教学中的创新应用路径。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>4月16日，外国语学院在东风校区语言实验中心举办了"AI赋能外语教学"专题研讨会。来自省内外8所高校的60余名外语教师参加了本次研讨。</p><p>研讨会围绕"大语言模型辅助外语写作教学"、"AI口语陪练系统的课堂应用"、"个性化外语学习路径智能推荐"等前沿话题展开深入交流。会议邀请了北京外国语大学梁茂成教授作题为"人工智能时代的外语教育变革"的主旨报告。本校外国语学院马超教授分享了"基于AI技术的外语写作智能反馈系统"的研发与应用经验。</p><p>外国语学院院长在总结中表示，学院将以此次研讨会为新起点，加快推动AI技术与外语教学的深度融合，探索"AI+外语"教学新模式。</p>', '2026-04-17 14:00:00', '221', '1', '70', '0', '2', 'admin', '2026-04-17 14:00:00', '', '2026-04-17 14:00:00', '0'),
('45', '我校获批4项省级教学改革研究重点项目', '省教育厅公布了2026年度省级教学改革研究项目立项名单，我校4个项目获批为重点项目，资助经费总额达80万元。', '', '<p>近日，河南省教育厅公布了2026年度省级教学改革研究项目立项名单，我校共有4个项目获批为重点项目，涵盖课程思政建设、实践教学体系改革、创新创业教育模式探索、教学质量保障机制优化四大领域，资助经费总额达80万元。</p><p>获批项目分别为：软件学院张伟副教授主持的"新工科视域下软件工程专业课程思政教学改革与实践"、电气信息工程学院郑丽教授主持的"基于OBE理念的自动化专业实践教学体系重构"、经济与管理学院杨帆副教授主持的"大数据驱动的经管类创新创业教育模式研究"、教务处主持的"地方高校教学质量保障体系优化研究"。</p><p>学校将以此次省级教改项目立项为契机，持续深化教育教学改革，高质量推进一流本科教育建设。</p>', '2026-04-10 08:30:00', '340', '1', '85', '0', '2', 'admin', '2026-04-10 08:30:00', '', '2026-04-10 08:30:00', '0'),
('46', '数学学院在全国大学生数学建模竞赛中再创佳绩', '2025年"高教社杯"全国大学生数学建模竞赛成绩揭晓，我校代表队获国家级一等奖3项、二等奖6项。', '', '<p>日前，2025年"高教社杯"全国大学生数学建模竞赛获奖名单正式公布。我校选派的30支参赛队伍中，共有24支队伍获奖，获奖率高达80%。其中，国家级一等奖3项、二等奖6项，省级一等奖8项、二等奖7项，获奖数量和质量均创历史新高。</p><p>全国大学生数学建模竞赛是由中国工业与应用数学学会主办的面向全国大学生的群众性科技活动，是首批列入"高校学科竞赛排行榜"的19项竞赛之一。2025年全国共有来自1600余所院校的5万余支队伍参赛。</p><p>数学与信息科学学院负责人表示，优异成绩的取得离不开指导教师的辛勤付出和学生的刻苦钻研，学院将继续以学科竞赛为牵引，推动数学教学改革和人才培养质量提升。</p>', '2026-03-15 10:00:00', '455', '1', '80', '0', '2', 'admin', '2026-03-15 10:00:00', '', '2026-03-15 10:00:00', '0'),
('47', '经济与管理学院举办"数字经济时代的管理教育"论坛', '4月8日，经济与管理学院举办学术论坛，探讨数字经济背景下管理学科教育改革的新理念、新路径。', '', '<p>4月8日，经济与管理学院在科学校区学术交流中心举办了"数字经济时代的管理教育"主题论坛。论坛邀请了中国人民大学、西安交通大学等高校的5位知名管理学者作学术报告。</p><p>论坛围绕"数字经济对管理教育的影响与挑战"、"大数据与AI在管理课程中的整合"、"新商科人才培养模式的转型"等议题进行了深入研讨。与会专家一致认为，数字经济时代的管理教育必须加快数字化转型，培养学生的数据思维、平台思维和创新思维。</p><p>经济与管理学院院长表示，学院将以此次论坛成果为指导，加快推进管理类课程的数字化转型，努力培养适应数字经济发展需求的高素质管理人才。</p>', '2026-04-09 11:00:00', '168', '1', '60', '0', '2', 'admin', '2026-04-09 11:00:00', '', '2026-04-09 11:00:00', '0'),
('48', '学校召开2026年本科教学工作推进会', '3月25日，学校召开本科教学工作推进会，部署2026年本科教学重点工作，强调以审核评估为契机全面提升教学质量。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>3月25日上午，郑州轻工业大学2026年本科教学工作推进会在科学校区办公楼第一会议室召开。校长出席会议并讲话，各学院院长、教学副院长、教务处全体人员参加会议。</p><p>会议部署了2026年本科教学八项重点工作：一是高质量推进一流专业和一流课程建设；二是深化课程思政教学改革；三是加强实践教学体系建设；四是做好本科教育教学审核评估迎评工作；五是推进教师教学能力提升工程；六是完善教学质量保障体系；七是深化产教融合协同育人；八是加快教育数字化转型。</p><p>校长在讲话中强调，各学院要以审核评估为契机，以评促建、以评促改，不断提升本科教育教学质量，为学校建设高水平轻工业大学贡献力量。</p>', '2026-03-26 09:00:00', '503', '1', '90', '0', '2', 'admin', '2026-03-26 09:00:00', '', '2026-03-26 09:00:00', '0'),
('49', '教务处完成新版教学成果管理平台上线运行', '经过三个月的开发测试，新版教学成果管理平台已于近日正式上线，实现了成果申报、审核、统计的全流程在线管理。', '', '<p>经过近三个月的紧张开发和测试，新版教学成果管理平台已于近日正式上线运行。该平台基于Spring Cloud微服务架构开发，实现了教学成果从申报、审核、公示到统计的全流程在线管理。</p><p>新版平台在功能上有以下亮点：一是支持富文本编辑器，教师可在线撰写成果详细内容并上传多种格式附件；二是支持多级审核流程，涵盖了院级初审和校级终审两个环节；三是提供丰富的统计分析和数据可视化功能，可按学院、类型、等级等维度生成统计报表；四是优化了门户展示功能，审核通过的成果可自动推送到门户网站公开展示。</p><p>平台上线以来，已有超过50位教师使用平台提交了教学成果申报，整体运行稳定。教务处将继续收集用户反馈，持续优化平台功能。</p>', '2026-03-10 10:00:00', '275', '1', '75', '0', '2', 'admin', '2026-03-10 10:00:00', '', '2026-03-10 10:00:00', '0');
